    public static function handle_post() {
        if ($_SERVER['REQUEST_METHOD'] !== 'POST') return;

        if (isset($_POST['spah_action']) && $_POST['spah_action'] === 'register') {
            self::handle_register();
        } elseif (isset($_POST['spah_action']) && $_POST['spah_action'] === 'login') {
            self::handle_login();
        }
    }

    private static function handle_register() {
        if (!isset($_POST[self::NONCE_REGISTER]) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST[self::NONCE_REGISTER])), self::NONCE_REGISTER)) {
            self::flash_error('Invalid request.');
            return;
        }

        $username = isset($_POST['username']) ? sanitize_user(wp_unslash($_POST['username']), true) : '';
        $email    = isset($_POST['email']) ? sanitize_email(wp_unslash($_POST['email'])) : '';
        $password = isset($_POST['password']) ? (string) wp_unslash($_POST['password']) : '';

        if ($username === '' || $email === '' || $password === '') {
            self::flash_error('All fields are required.');
            return;
        }

        if (!is_email($email)) {
            self::flash_error('Invalid email address.');
            return;
        }

        if (username_exists($username)) {
            self::flash_error('Username already exists.');
            return;
        }

        if (email_exists($email)) {
            self::flash_error('Email already exists.');
            return;
        }

        if (strlen($password) < 8) {
            self::flash_error('Password must be at least 8 characters.');
            return;
        }

        $user_id = wp_insert_user([
            'user_login' => $username,
            'user_email' => $email,
            'user_pass'  => wp_generate_password(64, true, true),
            'role'       => get_option('default_role', 'subscriber'),
        ]);

        if (is_wp_error($user_id)) {
            self::flash_error($user_id->get_error_message());
            return;
        }

        $hash = password_hash($password, PASSWORD_DEFAULT);
        if (!$hash) {
            wp_delete_user($user_id);
            self::flash_error('Failed to hash password.');
            return;
        }

        update_user_meta($user_id, '_spah_pass_hash', $hash);

        wp_set_current_user($user_id);
        wp_set_auth_cookie($user_id, true);

        self::flash_success('Registration successful. You are now logged in.');
        self::redirect_back();
    }

    private static function handle_login() {
        if (!isset($_POST[self::NONCE_LOGIN]) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST[self::NONCE_LOGIN])), self::NONCE_LOGIN)) {
            self::flash_error('Invalid request.');
            return;
        }

        $login    = isset($_POST['login']) ? sanitize_text_field(wp_unslash($_POST['login'])) : '';
        $password = isset($_POST['password']) ? (string) wp_unslash($_POST['password']) : '';

        if ($login === '' || $password === '') {
            self::flash_error('Both fields are required.');
            return;
        }

        $user = get_user_by('login', $login);
        if (!$user && is_email($login)) {
            $user = get_user_by('email', $login);
        }

        if (!$user) {
            self::flash_error('Invalid credentials.');
            return;
        }

        $hash = get_user_meta($user->ID, '_spah_pass_hash', true);

        if (!is_string($hash) || $hash === '') {
            self::flash_error('Account is not configured for this authentication method.');
            return;
        }

        $ok = password_verify($password, $hash);
        if (!$ok) {
            self::flash_error('Invalid credentials.');
            return;
        }

        if (password_needs_rehash($hash, PASSWORD_DEFAULT)) {
            $new_hash = password_hash($password, PASSWORD_DEFAULT);
            if ($new_hash) update_user_meta($user->ID, '_spah_pass_hash', $new_hash);
        }

        wp_set_current_user($user->ID);
        wp_set_auth_cookie($user->ID, true);

        self::flash_success('Login successful.');
        self::redirect_back();
    }

    public static function shortcode_register($atts = []) {
        if (is_user_logged_in()) {
            $logout_url = esc_url(add_query_arg('spah_logout', '1'));
            return '<div class="spah spah-logged-in">You are logged in. <a href="' . $logout_url . '">Log out</a></div>';
