        $html .= '<form class="spah spah-register" method="post" action="' . $action . '">';
        $html .= $nonce;
        $html .= '<input type="hidden" name="spah_action" value="register" />';
        $html .= '<p><label>Username<br /><input type="text" name="username" autocomplete="username" required /></label></p>';
