        $html = '';
        $html .= $msg;
        $html .= '<form class="spah spah-login" method="post" action="' . $action . '">';
        $html .= $nonce;
        $html .= '<input type="hidden" name="spah_action" value="login" />';
        $html .= '<p><label>Username or Email<br /><input type="text" name="login" autocomplete="username" required /></label></p>';
        $html .= '<p><label>Password<br /><input type="password" name="password" autocomplete="current-password" required /></label></p>';
        $html .= '<p><button type="submit">Log In</button></p>';
        $html .= '</form>';

        return $html;
    }

    private static function current_url() {
        $scheme = is_ssl() ? 'https' : 'http';
        $host = $_SERVER['HTTP_HOST'] ?? '';
        $uri  = $_SERVER['REQUEST_URI'] ?? '';
        $url = $scheme . '://' . $host . $uri;
        return remove_query_arg(['spah_msg', 'spah_err'], $url);
    }

    private static function redirect_back() {
        $url = self::current_url();
